Scripts.OnEnter:
if not this:IsEnabled() then
    GameTooltip:SetOwner(this, "ANCHOR_RIGHT");
    GameTooltip:SetText(this.disabledTooltip or "Cannot upgrade this item.", 1, 0.1, 0.1);
    GameTooltip:Show();
end

GameTooltip:SetOwner(self, "ANCHOR_RIGHT");
GameTooltip:SetText("Item Upgrade", 1, 1, 1);
GameTooltip:AddLine("Open the Standard Item Upgrade interface", 0.8, 0.8, 0.8, true);
GameTooltip:Show();

GameTooltip:SetOwner(self, "ANCHOR_RIGHT");
GameTooltip:SetText("Heirloom Upgrade", 1, 0.82, 0);
GameTooltip:AddLine("Open the Heirloom Upgrade interface", 0.8, 0.8, 0.8, true);
GameTooltip:Show();
